// applyIdentity fills in a default name for unnamed sensors and derives
// the sensor ID from the name. The ID is a hash rather than stored state
// so the same name always maps to the same ID, even if the data file is
// lost or a reading predates these fields.
func applyIdentity(r Reading) Reading {
	if r.SensorName == "" {
		r.SensorName = fmt.Sprintf("sensor@%.4f,%.4f", r.Latitude, r.Longitude)
	}
	sum := sha256.Sum256([]byte(r.SensorName))
	r.SensorID = hex.EncodeToString(sum[:4])
	return r
}

